using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any public type.
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣  GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed).
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣  TryGetTypeInfo<T>() — probe without throwing.
//     With the web defaults resolver every type resolves, so Person succeeds:
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {found!.Type.Name}");

// Now use options that only know about a *specific* type (via a source-gen context).
// Asking for an unregistered type will NOT throw — it just returns false.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = WidgetContext.Default
};

if (restrictedOptions.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("Person metadata found (unexpected)");
else
    Console.WriteLine("TryGetTypeInfo<Person> on restricted options → not available (no exception!)");

if (restrictedOptions.TryGetTypeInfo<Widget>(out JsonTypeInfo<Widget>? widgetInfo))
    Console.WriteLine($"TryGetTypeInfo<Widget> on restricted options → found, Type = {widgetInfo!.Type.Name}");

// --- Types ---
public record Person(string Name, int Age);
public record Widget(int Id, string Label);

// Source-gen context that only registers Widget.
[JsonSerializable(typeof(Widget))]
public partial class WidgetContext : JsonSerializerContext;

